from typing import List

def generate_possible_next_moves(s: str) -> List[str]:
    result = []
    for i in range(len(s) - 1):
        if s[i] == '+' and s[i + 1] == '+':
            result.append(s[:i] + '--' + s[i + 2:])
    return result
